# app/services/recording_incineration_service.rb
module Services
  class RecordingIncinerationService
    def initialize(recording)
      @recording = recording
    end

    def call
      ActiveRecord::Base.transaction do
        @recording.attachments.each(&:purge)
        @recording.events.destroy_all
        @recording.destroy!
      end
    end
  end
end
